import { MinPointSize } from 'recharts/types/util/BarUtils';
import { MaybeStackedGraphicalItem } from 'recharts/types/state/types/StackedGraphicalItem';
import { BaseCartesianGraphicalItemSettings } from 'recharts/types/state/graphicalItemsSlice';
export type BarSettings = BaseCartesianGraphicalItemSettings & MaybeStackedGraphicalItem & {
    type: 'bar';
    maxBarSize: number | undefined;
    minPointSize: MinPointSize;
    /**
     * When true, zero-dimension bars are not filtered out because the custom shape may still render something visible.
     */
    hasCustomShape: boolean;
};
